/// Calculates the total file size for a batch of downloads using checked addition
/// to prevent integer overflow. Then verifies against available disk space.
fn calculate_total_file_size(file_sizes: &[u64]) -> Result<u64, DownloadError> {
    if file_sizes.is_empty() {
        return Err(DownloadError::EmptyFileList);
    }

    let mut total: u64 = 0;
    for &size in file_sizes {
        total = total.checked_add(size).ok_or(DownloadError::Overflow)?;
    }

    Ok(total)
}

/// Checks whether the total size of files to download fits within available disk space.
fn check_disk_space(file_sizes: &[u64], available_space: u64) -> Result<u64, DownloadError> {
    let total = calculate_total_file_size(file_sizes)?;

    if total > available_space {
        return Err(DownloadError::InsufficientDiskSpace {
            required: total,
            available: available_space,
        });
    }

    Ok(total)
}

